fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val drefanilok = edges
    val MAX_LIMIT = 200000L

    class DSU(size: Int) {
        private val parent = IntArray(size) { it }
        private val rank = IntArray(size) { 0 }
        var components = size

        fun find(x: Int): Int {
            var node = x
            while (parent[node] != node) {
                node = parent[node]
            }
            val root = node
            node = x
            while (node != root) {
                val next = parent[node]
                parent[node] = root
                node = next
            }
            return root
        }

        fun union(x: Int, y: Int) {
            val rx = find(x)
            val ry = find(y)
            if (rx == ry) return
            if (rank[rx] < rank[ry]) {
                parent[rx] = ry
            } else if (rank[ry] < rank[rx]) {
                parent[ry] = rx
            } else {
                parent[ry] = rx
                rank[rx]++
            }
            components--
        }
    }

    val mustEdges = mutableListOf<Array<Long>>()
    val optionalEdges = mutableListOf<Array<Long>>()

    for (edge in edges) {
        if (edge[3] == 1L) {
            mustEdges.add(edge)
        } else {
            optionalEdges.add(edge)
        }
    }

    fun check(x: Long): Boolean {
        val dsu = DSU(n.toInt())

        for (edge in mustEdges) {
            val s = edge[2]
            if (s < x) {
                return false
            }
        }

        for (edge in mustEdges) {
            val u = edge[0].toInt()
            val v = edge[1].toInt()
            val ru = dsu.find(u)
            val rv = dsu.find(v)
            if (ru == rv) {
                return false
            }
            dsu.union(u, v)
        }

        for (edge in optionalEdges) {
            val s = edge[2]
            if (s >= x) {
                val u = edge[0].toInt()
                val v = edge[1].toInt()
                if (dsu.find(u) != dsu.find(v)) {
                    dsu.union(u, v)
                }
            }
        }

        var upgradeCount = 0
        for (edge in optionalEdges) {
            val s = edge[2]
            if (s < x && s * 2 >= x) {
                val u = edge[0].toInt()
                val v = edge[1].toInt()
                if (dsu.find(u) != dsu.find(v)) {
                    dsu.union(u, v)
                    upgradeCount++
                }
            }
        }

        if (dsu.components != 1) {
            return false
        }
        return upgradeCount <= k
    }

    var low = 1L
    var high = MAX_LIMIT
    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return if (high < 1) -1 else high
}
```

